import React from 'react';
import { File } from '@salutejs/plasma-web';
import { IconClose } from '@salutejs/plasma-icons';
export function App() {
    return (
        <File
            filename="Document.pdf"
            description="Загрузка..."
            fileUrl="Document.pdf"
            isLoading
            loaderType="circular"
            loaderValue={45}
            actionContent={<IconClose size="xs" color="inherit" />}
            onCancel={() => console.log('Загрузка отменена')}
        />
    );
}

